import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import { FiHome, FiBox, FiUsers, FiFileText, FiShoppingCart, FiTruck, FiChevronDown, FiChevronRight } from 'react-icons/fi';

const Sidebar = () => {
  const menuSections = [
    {
      title: 'Getting Started',
      items: [
        { path: '/dashboard', name: 'Home', icon: <FiHome /> },
        { path: '/items', name: 'Items', icon: <FiBox /> },
        {
          name: 'Sales',
          icon: <FiShoppingCart />,
          subitems: [
            { path: '/customers', name: 'Contact Management', icon: <FiUsers /> },
            { path: '/invoices', name: 'Invoice Creation', icon: <FiFileText /> }
          ]
        },
        {
          name: 'Purchase',
          icon: <FiTruck />,
          subitems: [
            { path: '/purchase-orders', name: 'Purchase Orders', icon: <FiShoppingCart /> },
            { path: '/vendors', name: 'Vendor Management', icon: <FiTruck /> }
          ]
        }
      ]
    }
  ];

  const [expandedSections, setExpandedSections] = useState(() => {
    const init = {};
    menuSections.forEach(s => { init[s.title] = s.title === 'Getting Started'; });
    return init;
  });

  const [expandedItems, setExpandedItems] = useState(() => {
    try {
      const raw = window.localStorage.getItem('sidebar_expandedItems');
      if (raw) return JSON.parse(raw);
    } catch (e) {
      // ignore
    }
    const init = {};
    menuSections.forEach(s => s.items.forEach(i => { if (i.subitems) init[i.name] = false; }));
    return init;
  });

  const toggleSection = (title) => {
    setExpandedSections(prev => ({ ...prev, [title]: !prev[title] }));
  };

  const toggleItem = (name) => {
    setExpandedItems(prev => {
      const next = { ...prev, [name]: !prev[name] };
      try { window.localStorage.setItem('sidebar_expandedItems', JSON.stringify(next)); } catch (e) {}
      return next;
    });
  };

  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <div className="sidebar-logo">INVOICE</div>
        <div className="sidebar-subtitle">Billing System</div>
      </div>
      <nav className="sidebar-nav">
        {menuSections.map((section, idx) => (
          <div key={idx} className="sidebar-nav-section">
            <div
              className="sidebar-nav-title"
              onClick={() => toggleSection(section.title)}
              style={{ cursor: 'pointer' }}
            >
              {section.title}
            </div>

            {expandedSections[section.title] && (
              <div className="sidebar-nav-items">
                {section.items.map(item => {
                  if (item.subitems) {
                    const isOpen = !!expandedItems[item.name];
                    return (
                      <div key={item.name}>
                        <div
                          className={`sidebar-nav-item ${isOpen ? 'open' : ''}`}
                          onClick={() => toggleItem(item.name)}
                          style={{ cursor: 'pointer', display: 'flex', alignItems: 'center' }}
                        >
                          <span className="nav-icon">{item.icon}</span>
                          <span style={{ marginLeft: 8 }}>{item.name}</span>
                          <span style={{ marginLeft: 'auto' }}>{isOpen ? '▾' : '▸'}</span>
                        </div>
                        {isOpen && (
                          <div className="sidebar-subitems" style={{ paddingLeft: 12 }}>
                            {item.subitems.map(sub => (
                              <NavLink key={sub.path} to={sub.path} className={({ isActive }) => `sidebar-nav-item ${isActive ? 'active' : ''}`}>
                                <span className="nav-icon">{sub.icon}</span>
                                <span style={{ marginLeft: 8 }}>{sub.name}</span>
                              </NavLink>
                            ))}
                          </div>
                        )}
                      </div>
                    );
                  }

                  return (
                    <NavLink key={item.path} to={item.path} className={({ isActive }) => `sidebar-nav-item ${isActive ? 'active' : ''}`}>
                      <span className="nav-icon">{item.icon}</span>
                      <span style={{ marginLeft: 8 }}>{item.name}</span>
                    </NavLink>
                  );
                })}
              </div>
            )}
          </div>
        ))}
      </nav>
      <div className="sidebar-footer">
        © 2026 Arshan UG<br />All rights reserved
      </div>
    </div>
  );
};

export default Sidebar;
